"use client"
import { useEffect, useRef } from "react"

interface TrailPoint { x: number; y: number; t: number }

export function CursorTrail({ color = "#00d4ff", size = 6, length = 20 }: {
  color?: string; size?: number; length?: number
}) {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const trail = useRef<TrailPoint[]>([])
  const raf = useRef(0)

  useEffect(() => {
    const canvas = canvasRef.current!
    const ctx = canvas.getContext("2d")!
    let W = 0, H = 0

    const resize = () => {
      W = canvas.width = window.innerWidth
      H = canvas.height = window.innerHeight
    }
    resize()
    window.addEventListener("resize", resize)

    const onMove = (e: MouseEvent) => {
      trail.current.push({ x: e.clientX, y: e.clientY, t: Date.now() })
      if (trail.current.length > length) trail.current.shift()
    }
    window.addEventListener("mousemove", onMove)

    const draw = () => {
      ctx.clearRect(0, 0, W, H)
      const now = Date.now()
      trail.current = trail.current.filter(p => now - p.t < 600)
      for (let i = 0; i < trail.current.length; i++) {
        const p = trail.current[i]
        const age = (now - p.t) / 600
        const alpha = (1 - age) * (i / trail.current.length)
        const r = size * (1 - age * 0.5)
        const grd = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, r * 3)
        grd.addColorStop(0, color.replace(")", `, ${alpha})`))
        grd.addColorStop(1, "rgba(0,0,0,0)")
        ctx.beginPath()
        ctx.arc(p.x, p.y, r * 3, 0, Math.PI * 2)
        ctx.fillStyle = grd
        ctx.fill()
      }
      raf.current = requestAnimationFrame(draw)
    }
    draw()

    return () => {
      cancelAnimationFrame(raf.current)
      window.removeEventListener("resize", resize)
      window.removeEventListener("mousemove", onMove)
    }
  }, [color, size, length])

  return (
    <canvas
      ref={canvasRef}
      className="pointer-events-none fixed inset-0 z-[9999]"
      aria-hidden
    />
  )
}
